 // Session status values. A session is running, has exited, or is paused — soft-
 // stopped with its tmux and worktree freed but its branch and record kept so it
 // can be resumed.
 const (
 	StatusRunning = "running"
 	StatusExited  = "exited"
 	StatusPaused  = "paused"
