// ChangedPaths returns the repository-relative paths changed in the worktree
// at worktreePath against baseCommit, both committed and still-uncommitted
// (staged, unstaged and untracked). It is the cheap, path-only counterpart to
// Diff: like DiffNumstat it first runs `git add -N .` so untracked files are
// visible to the diff, then reads `git diff --numstat <baseCommit>` and takes
// only the path column, skipping the added/removed counts. This is the source
// collision detection polls per tick, so it stays a numstat rather than a full
// diff. A clean worktree returns an empty, non-nil slice.
func (m *Manager) ChangedPaths(
	worktreePath, baseCommit string,
) ([]string, error) {
	if worktreePath == "" || baseCommit == "" {
		return nil, errors.New("worktree path and base commit required")
	}

	lock := indexLock(worktreePath)
	lock.Lock()
	defer lock.Unlock()

	if _, err := m.gitAt(worktreePath, "add", "-N", "."); err != nil {
		return nil, err
	}
	stat, err := m.gitAt(
		worktreePath, "--no-pager", "diff", "--numstat", baseCommit,
	)
	if err != nil {
		return nil, err
	}

	return parseNumstatPaths(stat), nil
}

// parseNumstatPaths extracts the path column of `git diff --numstat` output.
// Each line is "added\tremoved\tpath", except a rename, which numstat renders
// as "added\tremoved\told => new" (or "added\tremoved\t{old => new}/rest" when
// only part of the path changed); in both cases the path after "=> " is taken
// as the changed path, matching the working tree's current name.
func parseNumstatPaths(out []byte) []string {
	paths := make([]string, 0)
	for line := range strings.SplitSeq(string(out), "\n") {
		line = strings.TrimSpace(line)
		if line == "" {
			continue
		}
		fields := strings.SplitN(line, "\t", 3)
		if len(fields) < 3 {
			continue
		}
		paths = append(paths, renamedPath(fields[2]))
	}
	return paths
}

// renamedPath resolves a numstat path field to the file's current name,
// unwrapping git's "old => new" and "{old => new}" rename notations.
func renamedPath(field string) string {
	if idx := strings.Index(field, "=>"); idx != -1 {
		newPart := strings.TrimSpace(field[idx+len("=>"):])
		newPart = strings.TrimSuffix(newPart, "}")
		if braceIdx := strings.Index(field, "{"); braceIdx != -1 {
			prefix := field[:braceIdx]
			return prefix + newPart
		}
		return newPart
	}
	return field
}

