		added, _ := strconv.Atoi(fields[0])
		removed, _ := strconv.Atoi(fields[1])
		entries = append(entries, NumstatEntry{
			Path:    renamedPath(fields[2]),
			Added:   added,
			Removed: removed,
		})
	}
	return entries
}

