		{ID: "s1", WorkspaceID: "ws1", Branch: "feature/a", WorktreePath: wt1, BaseCommit: base, Status: registry.StatusRunning},
		{ID: "s2", WorkspaceID: "ws1", Branch: "feature/b", WorktreePath: wt2, BaseCommit: base, Status: registry.StatusRunning},
	}
	diff := func(_, worktreePath, baseCommit string) ([]string, error) {
		return worktree.New(repo, home, "ws1").ChangedPaths(worktreePath, baseCommit)
	}
	changed := collision.ChangedPaths(sessions, diff)
